mod c_api;
mod call_request;
mod consent_request;
mod resources;
mod ui;
mod verify_certificate;

#[cfg(test)]
mod ffi_verify_cert {
    use crate::{constants::CANISTER_ROOT_KEY, error::ParserError};

    use super::{
        call_request::rs_parse_canister_call_request, consent_request::rs_parse_consent_request,
        resources::rs_clear_resources, verify_certificate::rs_verify_certificate,
    };

    const CERT_DATA: &str = "";
    const CALL_DATA: &str ="d9d9f7a167636f6e74656e74a6636172674c4449444c00017104746f62696b63616e69737465725f69644a00000000006000fd01016e696e67726573735f657870697279c24817c49d610e2008806b6d6574686f645f6e616d656567726565746c726571756573745f747970656571756572796673656e6465724104";
    const CONSENT_DATA: &str = "";

    const CERT2: &str = "";
    const CALL2: &str = "";
    const CONSENT2: &str = "";

    const CERT3: &str = "";
    const CALL3: &str = "";
    const CONSENT3: &str = "";

    fn bls_flow(cert: &str, call: &str, consent: &str) -> u32 {
        let cert_data = hex::decode(cert).unwrap();
        let call_data = hex::decode(call).unwrap();
        let consent_data = hex::decode(consent).unwrap();
        let root_key = hex::decode(CANISTER_ROOT_KEY).unwrap();

        unsafe {
            // 1. send consent_request
            if rs_parse_consent_request(consent_data.as_ptr(), consent_data.len() as u16)
                != ParserError::Ok as _
            {
                return ParserError::InvalidConsentMsg as u32;
            }

            // 2. send call request
            if rs_parse_canister_call_request(call_data.as_ptr(), call_data.len() as u16)
                != ParserError::Ok as _
            {
                return ParserError::InvalidCallRequest as u32;
            }
            // 3. send certificate, by default use root key
            if rs_verify_certificate(
                cert_data.as_ptr(),
                cert_data.len() as u16,
                root_key.as_ptr(),
            ) != ParserError::Ok as _
            {
                return ParserError::InvalidCertificate as u32;
            }

            ParserError::Ok as u32
        }
    }

    #[test]
    fn test_bls_flow() {
        assert_eq!(
            bls_flow(CERT_DATA, CALL_DATA, CONSENT_DATA),
            ParserError::Ok as u32
        );
        unsafe {
            rs_clear_resources();
        }

        // now test again and ensure we error if resources are not empty
        assert_eq!(
            bls_flow(CERT_DATA, CALL_DATA, CONSENT_DATA),
            ParserError::Ok as u32
        );
        // trying to verify without cleaning resources
        assert_ne!(
            bls_flow(CERT_DATA, CALL_DATA, CONSENT_DATA),
            ParserError::Ok as u32
        );
    }

    #[test]
    fn test_bls_flow_with_app_signer() {
        assert_eq!(bls_flow(CERT2, CALL2, CONSENT2), ParserError::Ok as u32);
    }
}
